import asyncio
import websockets
import json
from collections import defaultdict

class Player:
    def __init__(self, name):
        self.name = name
        self.inventory = defaultdict(int)

    def add_item(self, item, quantity):
        self.inventory[item] += quantity

    def remove_item(self, item, quantity):
        if self.inventory[item] >= quantity:
            self.inventory[item] -= quantity
            return True
        return False

    def get_inventory(self):
        return dict(self.inventory)

class GameServer:
    def __init__(self):
        self.players = {}
        self.lock = asyncio.Lock()

    async def handler(self, websocket, path):
        player_name = await websocket.recv()
        self.players[player_name] = Player(player_name)

        try:
            async for message in websocket:
                await self.process_message(player_name, message)
        finally:
            del self.players[player_name]

    async def process_message(self, player_name, message):
        data = json.loads(message)
        action = data.get("action")

        if action == "trade":
            await self.handle_trade(player_name, data)

    async def handle_trade(self, player_name, data):
        from_player = self.players[player_name]
        to_player_name = data['to']
        item = data['item']
        quantity = data['quantity']

        async with self.lock:
            if to_player_name in self.players:
                to_player = self.players[to_player_name]
                if from_player.remove_item(item, quantity):
                    to_player.add_item(item, quantity)
                    await self.notify_players(from_player, to_player, item, quantity)

    async def notify_players(self, from_player, to_player, item, quantity):
        trade_message = {
            "action": "trade_success",
            "from": from_player.name,
            "to": to_player.name,
            "item": item,
            "quantity": quantity
        }
        await self.send_message(from_player.name, trade_message)
        await self.send_message(to_player.name, trade_message)

    async def send_message(self, player_name, message):
        websocket = self.players[player_name]
        await websocket.send(json.dumps(message))

    def run(self):
        start_server = websockets.serve(self.handler, "localhost", 8765)
        asyncio.get_event_loop().run_until_complete(start_server)
        asyncio.get_event_loop().run_forever()

if __name__ == "__main__":
    server = GameServer()
    server.run()